# Import necessary libraries
import pandas as pd
import numpy as np
from sklearn.pipeline import Pipeline, ColumnTransformer
from sklearn.impute import SimpleImputer, IterativeImputer
from sklearn.preprocessing import StandardScaler, MinMaxScaler, RobustScaler, OneHotEncoder, TargetEncoder, PCA
from sklearn.compose import make_column_selector
from sklearn.model_selection import train_test_split, cross_val_score
from sklearn.ensemble import RandomForestClassifier, GradientBoostingClassifier, LightGBMClassifier
from sklearn.linear_model import LogisticRegression
import pickle

# Load new data from CSV
def load_new_data(file_path):
    try:
        return pd.read_csv(file_path)
    except FileNotFoundError as e:
        print(f"Error: {e}")
        return None

# Load saved preprocessing pipeline
def load_preprocessing_pipeline(pipeline_file_path):
    try:
        with open(pipeline_file_path, 'rb') as file:
            return pickle.load(file)
    except FileNotFoundError as e:
        print(f"Error: {e}")
        return None

# Load saved trained model
def load_trained_model(model_file_path):
    try:
        with open(model_file_path, 'rb') as file:
            return pickle.load(file)
    except FileNotFoundError as e:
        print(f"Error: {e}")
        return None

# Preprocess new data using the loaded pipeline
def preprocess_data(data, preprocessing_pipeline):
    try:
        return preprocessing_pipeline.transform(data)
    except Exception as e:
        print(f"Error during preprocessing: {e}")
        return None

# Make predictions on preprocessed data
def make_predictions(preprocessed_data, model):
    try:
        probabilities = model.predict_proba(preprocessed_data)[:, 1]
        return probabilities
    except Exception as e:
        print(f"Error during prediction: {e}")
        return None

# Apply threshold to probabilities and save predictions to CSV
def apply_threshold_and_save_predictions(probabilities, threshold, output_file_path):
    try:
        predictions = (probabilities >= threshold).astype(int)
        df_predictions = pd.DataFrame({'probability': probabilities, 'prediction': predictions})
        df_predictions.to_csv(output_file_path, index=False)
        print(f"Predictions saved to {output_file_path}")
    except Exception as e:
        print(f"Error during prediction saving: {e}")

# Main function
def main():
    # Load new data
    file_path = 'new_data.csv'
    new_data = load_new_data(file_path)

    if new_data is not None:
        # Load preprocessing pipeline and trained model
        pipeline_file_path = 'preprocessing_pipeline.pkl'
        model_file_path = 'trained_model.pkl'

        preprocessing_pipeline = load_preprocessing_pipeline(pipeline_file_path)
        model = load_trained_model(model_file_path)

        if preprocessing_pipeline is not None and model is not None:
            # Preprocess new data
            preprocessed_data = preprocess_data(new_data, preprocessing_pipeline)

            if preprocessed_data is not None:
                # Make predictions
                probabilities = make_predictions(preprocessed_data, model)

                if probabilities is not None:
                    # Apply threshold and save predictions to CSV
                    output_file_path = 'predictions.csv'
                    apply_threshold_and_save_predictions(probabilities, 0.5, output_file_path)

if __name__ == "__main__":
    main()
